import{_ as a,o as l,c as i,a9 as r}from"./chunks/framework.STMWz9Nm.js";const p=JSON.parse('{"title":"典型应用场景","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/14-ZooKeeper学习/05-典型应用场景.md","filePath":"语言/java/14-ZooKeeper学习/05-典型应用场景.md","lastUpdated":1776149370000}'),o={name:"语言/java/14-ZooKeeper学习/05-典型应用场景.md"};function t(h,e,_,n,d,s){return l(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="典型应用场景" tabindex="-1">典型应用场景 <a class="header-anchor" href="#典型应用场景" aria-label="Permalink to “典型应用场景”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>这一篇主要把 ZooKeeper 的能力和真实系统场景对应起来。<br> 重点不是再讲概念，而是理解它为什么会被这么多中间件依赖。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>只有把能力映射到场景，ZooKeeper 的价值才会真正清晰。<br> 这也能帮助你判断什么时候该用，什么时候不该用。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>注册中心</li><li>配置中心</li><li>分布式锁</li><li>选主与主备切换</li><li>集群成员管理</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解 ZooKeeper 更适合“协调元数据”场景</li><li>理解典型应用背后都依赖节点、会话和 Watcher</li><li>理解不是所有分布式问题都要用 ZooKeeper</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>把 ZooKeeper 当成万能协调组件</li><li>不结合访问量和数据模型判断适用性</li><li>过度依赖 ZooKeeper 承载业务数据</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>为一个注册中心场景画节点结构图</li><li>总结 ZooKeeper 和配置中心的关系</li><li>分析哪些问题更适合别的组件而不是 ZooKeeper</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>ZooKeeper 最典型的几个应用场景是什么</li><li>为什么 ZooKeeper 更适合管理元数据</li><li>什么场景下不适合用 ZooKeeper</li></ul>',15)])])}const b=a(o,[["render",t]]);export{p as __pageData,b as default};
